// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Exchange a wallet signature for a JWT bearer token
	// (POST /auth:exchange)
	AuthExchange(ctx context.Context, request AuthExchangeRequestObject) (AuthExchangeResponseObject, error)
	// List executions
	// (GET /executions)
	ListExecutions(ctx context.Context, request ListExecutionsRequestObject) (ListExecutionsResponseObject, error)
	// Retrieve an execution (full payload with steps)
	// (GET /executions/{id})
	GetExecution(ctx context.Context, request GetExecutionRequestObject) (GetExecutionResponseObject, error)
	// Get execution status (lightweight, no steps)
	// (GET /executions/{id}:getStatus)
	GetExecutionStatus(ctx context.Context, request GetExecutionStatusRequestObject) (GetExecutionStatusResponseObject, error)
	// Stream execution status changes (Server-Sent Events)
	// (GET /executions/{id}:stream)
	StreamExecution(ctx context.Context, request StreamExecutionRequestObject) (StreamExecutionResponseObject, error)
	// Count executions
	// (GET /executions:count)
	CountExecutions(ctx context.Context, request CountExecutionsRequestObject) (CountExecutionsResponseObject, error)
	// Execution statistics (totals + averages)
	// (GET /executions:stats)
	ExecutionStats(ctx context.Context, request ExecutionStatsRequestObject) (ExecutionStatsResponseObject, error)
	// Liveness probe
	// (GET /health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Execute a single node with inline input variables
	// (POST /nodes:run)
	RunNode(ctx context.Context, request RunNodeRequestObject) (RunNodeResponseObject, error)
	// List connected operators
	// (GET /operators)
	ListOperators(ctx context.Context, request ListOperatorsRequestObject) (ListOperatorsResponseObject, error)
	// List secrets (metadata only — values are never echoed)
	// (GET /secrets)
	ListSecrets(ctx context.Context, request ListSecretsRequestObject) (ListSecretsResponseObject, error)
	// Delete a secret
	// (DELETE /secrets/{name})
	DeleteSecret(ctx context.Context, request DeleteSecretRequestObject) (DeleteSecretResponseObject, error)
	// Create or replace a secret (idempotent)
	// (PUT /secrets/{name})
	PutSecret(ctx context.Context, request PutSecretRequestObject) (PutSecretResponseObject, error)
	// Retrieve ERC-20 token metadata
	// (GET /tokens/{address})
	GetToken(ctx context.Context, request GetTokenRequestObject) (GetTokenResponseObject, error)
	// Evaluate a trigger definition with inline input
	// (POST /triggers:run)
	RunTrigger(ctx context.Context, request RunTriggerRequestObject) (RunTriggerResponseObject, error)
	// List the authenticated user's smart wallets
	// (GET /wallets)
	ListWallets(ctx context.Context, request ListWalletsRequestObject) (ListWalletsResponseObject, error)
	// Derive (and persist) a smart wallet address from (owner, salt, factory)
	// (POST /wallets)
	CreateWallet(ctx context.Context, request CreateWalletRequestObject) (CreateWalletResponseObject, error)
	// Update wallet properties
	// (PATCH /wallets/{address})
	UpdateWallet(ctx context.Context, request UpdateWalletRequestObject) (UpdateWalletResponseObject, error)
	// Get the smart wallet's current nonce
	// (GET /wallets/{address}:getNonce)
	GetWalletNonce(ctx context.Context, request GetWalletNonceRequestObject) (GetWalletNonceResponseObject, error)
	// Withdraw funds from a smart wallet
	// (POST /wallets/{address}:withdraw)
	WithdrawWallet(ctx context.Context, request WithdrawWalletRequestObject) (WithdrawWalletResponseObject, error)
	// List workflows
	// (GET /workflows)
	ListWorkflows(ctx context.Context, request ListWorkflowsRequestObject) (ListWorkflowsResponseObject, error)
	// Create a workflow
	// (POST /workflows)
	CreateWorkflow(ctx context.Context, request CreateWorkflowRequestObject) (CreateWorkflowResponseObject, error)
	// Cancel a workflow
	// (DELETE /workflows/{id})
	CancelWorkflow(ctx context.Context, request CancelWorkflowRequestObject) (CancelWorkflowResponseObject, error)
	// Retrieve a workflow
	// (GET /workflows/{id})
	GetWorkflow(ctx context.Context, request GetWorkflowRequestObject) (GetWorkflowResponseObject, error)
	// List executions for a workflow (convenience nested route)
	// (GET /workflows/{id}/executions)
	ListExecutionsForWorkflow(ctx context.Context, request ListExecutionsForWorkflowRequestObject) (ListExecutionsForWorkflowResponseObject, error)
	// Pause a workflow
	// (POST /workflows/{id}:pause)
	PauseWorkflow(ctx context.Context, request PauseWorkflowRequestObject) (PauseWorkflowResponseObject, error)
	// Resume a workflow
	// (POST /workflows/{id}:resume)
	ResumeWorkflow(ctx context.Context, request ResumeWorkflowRequestObject) (ResumeWorkflowResponseObject, error)
	// Manually trigger a workflow
	// (POST /workflows/{id}:trigger)
	TriggerWorkflow(ctx context.Context, request TriggerWorkflowRequestObject) (TriggerWorkflowResponseObject, error)
	// Count workflows
	// (GET /workflows:count)
	CountWorkflows(ctx context.Context, request CountWorkflowsRequestObject) (CountWorkflowsResponseObject, error)
	// Estimate per-execution fees for a workflow definition
	// (POST /workflows:estimateFees)
	EstimateWorkflowFees(ctx context.Context, request EstimateWorkflowFeesRequestObject) (EstimateWorkflowFeesResponseObject, error)
	// Simulate a workflow without persisting it
	// (POST /workflows:simulate)
	SimulateWorkflow(ctx context.Context, request SimulateWorkflowRequestObject) (SimulateWorkflowResponseObject, error)
}

type StrictHandlerFunc func(ctx echo.Context, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares}
}

